SELECT id, mushroom_id, content_type, title, author_id, publish_date, praise_count, review_count, collect_count, content, video_url, description, source_url, content_status, audit_time, reject_reason, create_time FROM mh_popsci_content WHERE 1=1
AND content_status = 2
AND content_type = #{contentType}
ORDER BY RAND() LIMIT #{limit}

SELECT mushroom_id FROM mh_popsci_content WHERE id IN
#{contentId}
AND mushroom_id IS NOT NULL AND content_status = 2

SELECT id, mushroom_id, content_type, title, author_id, publish_date, praise_count, review_count, collect_count, content, video_url, description, source_url, content_status, audit_time, reject_reason, create_time FROM mh_popsci_content WHERE 1=1 AND mushroom_id IN
#{mushroomId}
AND id NOT IN
#{contentId}
AND content_status = 2
ORDER BY FIELD(mushroom_id,
#{mushroomId}
) DESC,
LIMIT #{limit}

SELECT id, mushroom_id, content_type, title, author_id, publish_date, praise_count, review_count, collect_count, content, video_url, description, source_url, content_status, audit_time, reject_reason, create_time FROM mh_popsci_content WHERE 1=1 AND mushroom_id IN
#{mushroomId}
AND content_type = #{contentType} AND id NOT IN
#{contentId}
AND content_status = 2
ORDER BY FIELD(mushroom_id,
#{mushroomId}
) DESC,
LIMIT #{limit}

SELECT FROM mh_popsci_content WHERE mushroom_id IN
#{id}
AND content_type = #{contentType} AND content_status = 2 -- 仅审核通过 AND id NOT IN
#{id}
-- 4. 只推荐已审核通过的内容 AND content_status = 2 ORDER BY -- 核心：直接写死权重计算公式（点赞*0.6 + 收藏*0.3 + 评论*0.1） (COALESCE(praise_count, 0) * 0.6 + COALESCE(collect_count, 0) * 0.3 + COALESCE(review_count, 0) * 0.1) DESC, publish_date DESC LIMIT #{candidateCount}


SELECT
id, mushroom_id, content_type, title, author_id, publish_date,
praise_count, review_count, collect_count, content, video_url,
description, source_url, content_status, audit_time, reject_reason, create_time
FROM mh_popsci_content



        AND (
                title LIKE CONCAT('%', #{keyword}, '%')
                OR description LIKE CONCAT('%', #{keyword}, '%')
            )




        AND mushroom_id = #{mushroomId}




        AND content_type = #{contentType}




        AND author_id = #{authorId}




        AND content_status = #{contentStatus}



ORDER BY publish_date DESC, create_time DESC

SELECT c.id, c.content_type as contentType, c.title, u.username as authorName, c.publish_date as publishDate, c.content_status as contentStatus, c.description, m.mushroom_name as mushroomName, -- 取第一个图片作为封面 (SELECT p.pic_url FROM mh_picture p WHERE p.content_id = c.id AND p.type = '图文详情图' LIMIT 1) as articleCoverUrl, (SELECT p.pic_url FROM mh_picture p WHERE p.content_id = c.id AND p.type = '视频封面' LIMIT 1) as videoCoverUrl FROM mh_popsci_content c LEFT JOIN mh_user u ON c.author_id = u.user_id LEFT JOIN mh_mushroom_info m ON c.mushroom_id = m.id WHERE c.author_id = #{dto.userId}
AND c.content_type = #{dto.mediaType.code}
ORDER BY c.publish_date DESC LIMIT #{dto.pageSize} OFFSET #{offset} -- 分页（offset = (pageNum-1)*pageSize）

SELECT COUNT(*)
FROM mh_popsci_content c
WHERE c.author_id = #{dto.userId}

    AND c.content_type = #{dto.mediaType.code}
